// Look up client by name, email domain, or ClickUp space ID
const trigger = $('Sub-Workflow Input').first().json;
const clients = $input.all().map(item => item.json);

const lookupType = trigger.lookup_type;
const lookupValue = trigger.lookup_value?.toLowerCase();

let match = null;

if (lookupType === 'name') {
  match = clients.find(c => 
    c['Client Name']?.toLowerCase().includes(lookupValue)
  );
} else if (lookupType === 'email_domain') {
  // Extract domain from email and match against primary contact email
  match = clients.find(c => {
    const contactEmail = c['Primary Contact Email']?.toLowerCase() || '';
    const contactDomain = contactEmail.split('@')[1];
    return contactDomain === lookupValue || contactEmail.includes(lookupValue);
  });
} else if (lookupType === 'clickup_space') {
  match = clients.find(c => c['ClickUp Space ID'] === trigger.lookup_value);
}

if (!match) {
  return [{ json: { found: false, lookup_type: lookupType, lookup_value: lookupValue } }];
}

return [{
  json: {
    found: true,
    client_name: match['Client Name'],
    status: match['Status'],
    clickup_space_id: match['ClickUp Space ID'],
    google_drive_folder_id: match['Google Drive Folder ID'],
    onedrive_folder_path: match['OneDrive Folder Path'],
    primary_contact_email: match['Primary Contact Email'],
    primary_contact_name: match['Primary Contact Name'],
    cc_emails: match['CC Emails'],
    forecast_sheet_id: match['Forecast Sheet ID'],
    meeting_day: match['Meeting Day'],
    meeting_time: match['Meeting Time'],
    update_preference: match['Update Preference'],
    retainer_hours: match['Retainer Hours/Month'],
    hourly_rate: match['Hourly Rate'],
    toggl_project_id: match['Toggl Project ID'],
    hubspot_deal_id: match['HubSpot Deal ID'],
    linkedin_company_url: match['LinkedIn Company URL'],
    slack_channel: match['Slack Channel'],
    notes: match['Notes']
  }
}];
